#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=1e6+6;

int n,ans;
bool match[N];
pair<int,int> a[N];
map<pair<int,int>,int> mp;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&a[i].x,&a[i].y);
    sort(a+1,a+n+1);
    reverse(a+1,a+n+1);
    match[0]=1;
    for(int i=1;i<=n;i++){
        //printf("%d %d\n",a[i].x,a[i].y);
        int ta=mp[make_pair(a[i].x+1,a[i].y+1)];
        int tb=mp[make_pair(a[i].x+1,a[i].y)];
        int tc=mp[make_pair(a[i].x+1,a[i].y-1)];
        //printf("%d %d %d\n",ta,tb,tc);
        if(!match[ta])
            match[ta]=1;
        else if(!match[tb])
            match[tb]=1;
        else if(!match[tc])
            match[tc]=1;
        else
            ans++;
        mp[a[i]]=i;
    }
    printf("%d",ans);
    return 0;
}
